async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, {x, y});
  };

  const getState = () => page.evaluate(() => window.__latestGameState);
  const getSkills = () => page.evaluate(() => {
    const s = window.game.player.skills;
    const r = {};
    for (const k in s) if (s[k] && s[k].name) r[s[k].name] = {level: s[k].level, xp: s[k].experience};
    return r;
  });

  let kills = 0;

  // Do 3 attack cycles (max 2.5 min total)
  for (let i = 0; i < 3; i++) {
    const state = await getState();
    const hp = state.player_stats.hp;
    const maxHp = state.player_stats.max_hp;

    // Heal if HP < 40%
    if (hp < maxHp * 0.4) {
      const food = state.inventory.find(item => item.edible);
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(1000);
      }
    }

    // Find nearest on-screen rat
    const rats = state.nearby_entities.filter(e => e.name === 'Rat' && e.on_screen && e.click_x);
    if (rats.length > 0) {
      const rat = rats[0];
      await click(rat.click_x, rat.click_y);
      await page.waitForTimeout(10000); // wait for combat
    } else {
      // Walk east to find more rats
      await click(900, 400);
      await page.waitForTimeout(3000);
    }
  }

  const skills = await getSkills();
  const finalState = await getState();
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });

  return JSON.stringify({
    hp: finalState.player_stats.hp,
    pos: finalState.player_position,
    skills: {Strength: skills.Strength, Defense: skills.Defense, Health: skills.Health, Loitering: skills.Loitering},
    lastCombat: finalState.last_combat
  });
}

