async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, {x, y});
  };
  const getLogCount = (state) => state.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0);

  // Chop more trees (need 7 more logs)
  for (let i = 0; i < 10; i++) {
    const state = await page.evaluate(() => window.__latestGameState);
    const totalLogs = getLogCount(state);
    if (totalLogs >= 10) break;

    // Heal if needed
    if (state.player_stats.hp < state.player_stats.max_hp * 0.4) {
      const food = state.inventory.find(item => item.edible);
      if (food) await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
    }

    const oaks = state.nearby_entities.filter(e => e.name === 'Oak' && e.on_screen && e.click_x);
    if (oaks.length > 0) {
      await click(oaks[0].click_x, oaks[0].click_y);
    } else {
      await click(500, 400); // Walk west toward more trees
    }
    await page.waitForTimeout(4000);
  }

  const finalState = await page.evaluate(() => window.__latestGameState);
  const totalLogs = getLogCount(finalState);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify({
    totalLogs, inventory: finalState.inventory,
    hp: finalState.player_stats.hp + '/' + finalState.player_stats.max_hp,
    pos: finalState.player_position
  });
}

async (page) => {
  const click = async (x, y) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, {x, y});
  };
  const getLogCount = (state) => state.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0);

  // Try different oak trees - explore different positions
  const treePositions = [
    {x: 800, y: 300}, {x: 400, y: 300}, {x: 700, y: 500}, 
    {x: 300, y: 200}, {x: 900, y: 200}, {x: 600, y: 500}
  ];
  let idx = 0;

  for (let i = 0; i < 12; i++) {
    const state = await page.evaluate(() => window.__latestGameState);
    const totalLogs = getLogCount(state);
    if (totalLogs >= 10) break;

    // Heal if HP low
    if (state.player_stats.hp < state.player_stats.max_hp * 0.4) {
      const food = state.inventory.find(item => item.edible);
      if (food) {
        await page.evaluate((slot) => window.game.menu.getInventory().selectEdible(slot), food.slot);
        await page.waitForTimeout(500);
        continue;
      }
    }

    // Try each oak on screen first, then explore
    const oaks = state.nearby_entities.filter(e => e.name === 'Oak' && e.on_screen && e.click_x);
    if (oaks.length > 0) {
      // Try the next oak (rotate through them to avoid depleted trees)
      const oak = oaks[i % oaks.length];
      await click(oak.click_x, oak.click_y);
    } else {
      const pos = treePositions[idx++ % treePositions.length];
      await click(pos.x, pos.y);
    }
    await page.waitForTimeout(4500);
  }

  const finalState = await page.evaluate(() => window.__latestGameState);
  const totalLogs = getLogCount(finalState);
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify({
    totalLogs,
    inventory: finalState.inventory.map(i => i.name + 'x' + i.count),
    hp: finalState.player_stats.hp + '/' + finalState.player_stats.max_hp,
    pos: finalState.player_position
  });
}

