async (page) => {
  const click = (x, y) => page.evaluate(({x, y}) => {
    document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, {x, y});

  let logs = 8;
  let prevLogs = 8;
  let stuckCount = 0;

  for (let round = 0; round < 15 && logs < 10; round++) {
    const hp = await page.evaluate(() => window.__latestGameState.player_stats.hp);
    if (hp < 35) break;

    const oaks = await page.evaluate(() =>
      window.__latestGameState.nearby_entities
        .filter(e => e.name === 'Oak' && e.on_screen && e.click_x)
        .sort((a, b) => a.distance - b.distance)
        .slice(0, 3)
        .map(e => ({dist: e.distance, cx: e.click_x, cy: e.click_y}))
    );

    if (oaks.length > 0) {
      for (const oak of oaks) {
        await click(oak.cx, oak.cy);
        await page.waitForTimeout(4000);
        logs = await page.evaluate(() => (window.__latestGameState.inventory || []).filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0));
        if (logs > prevLogs) { prevLogs = logs; stuckCount = 0; break; }
      }
    }

    if (logs === prevLogs) {
      stuckCount++;
      if (stuckCount >= 2) {
        await click(640, 720);
        await page.waitForTimeout(2500);
        stuckCount = 0;
      }
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, hp: s.player_stats.hp, logs: (s.inventory || []).filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0) };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_1/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

